INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "あたしだって\nやるときはやるよ！", 0.0, "リン", 1, "2020/04/30 12:00:00", 10040, 0.0, "2030/12/17 14:59:59", 24001, 102601, 0, 1, 24);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "ふぅ…\nこれであたしの仕事は\n終わりだね", 0.0, "リン", 1, "2020/04/30 12:00:00", 10040, 0.0, "2030/12/17 14:59:59", 24002, 102601, 1, 1, 24);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "終わった終わった\n一人でもなんとか\nなるもんだね", 0.0, "リン", 1, "2020/04/30 12:00:00", 10040, 0.0, "2030/12/17 14:59:59", 24003, 102601, 2, 1, 24);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "やったね！\nこれでようやく\nサボれるよ…", 0.0, "リン", 2, "2020/04/30 12:00:00", 10040, 0.0, "2030/12/17 14:59:59", 24004, 102601, 3, 2, 24);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "チーズが欲しいなら\nきちんと働いて\n買いに来なよ", 0.0, "リン", 1, "2020/04/30 12:00:00", 10040, 0.0, "2030/12/17 14:59:59", 24005, 102601, 4, 1, 24);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "あたしを敵に回した\n恐ろしさ\n思い知ったか！", 0.0, "リン", 2, "2020/04/30 12:00:00", 10040, 0.0, "2030/12/17 14:59:59", 24006, 102601, 5, 2, 24);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "あたしも意外と\nやるもんでしょ？", 0.0, "リン", 2, "2020/04/30 12:00:00", 10040, 0.0, "2030/12/17 14:59:59", 24007, 102601, 6, 2, 24);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "疲れた…\nねずみの逃げ足\n速すぎるよ…", 0.0, "リン", 4, "2020/04/30 12:00:00", 10040, 0.0, "2030/12/17 14:59:59", 24008, 102601, 7, 4, 24);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "このままじゃ\nまっひ～に\n叱られちゃうよ", 0.0, "リン", 4, "2020/04/30 12:00:00", 10040, 0.0, "2030/12/17 14:59:59", 24009, 102601, 8, 4, 24);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "まじめに\nやったんだけどな…\n悔しいな～", 0.0, "リン", 4, "2020/04/30 12:00:00", 10040, 0.0, "2030/12/17 14:59:59", 24010, 102601, 9, 4, 24);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "やられた…\nねずみって意外と\nてごわいね", 0.0, "リン", 4, "2020/04/30 12:00:00", 10040, 0.0, "2030/12/17 14:59:59", 24011, 102601, 10, 4, 24);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "おのれ～\nあたしのチーズを\n盗みやがって～！", 0.0, "リン", 4, "2020/04/30 12:00:00", 10040, 0.0, "2030/12/17 14:59:59", 24012, 102601, 11, 4, 24);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (1.81, "疲れた…\nけど、次こそは\n守り抜くよ…", 0.0, "リン", 1, "2020/04/30 12:00:00", 10040, 0.0, "2030/12/17 14:59:59", 24013, 102601, 12, 4, 24);
